/*
•:•.•:•.•:•:•:•:•:•:•:••:•.•:•.•:•:•:•:•:•:•:•:•.•:•.•:•:•:•:•:•:•:••:•.•:•.•:•.•:•:•:•:•:•:•:•:•.•:•:•.•:•.••:•.•:•.••:
........................................................................................................................
☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦ ⠂⠄⠄⠂⠁⠁⠂⠄⠂⠄⠄⠂☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦ ⠂⠄⠄⠂⠁⠁⠂⠄⠂⠄⠄⠂☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦
    This script does the following:
    - Tracks when was the last time you've completed an activity that doesn't reset at midnight NST
    - Displays a notification whenever that activity resets
    - Allows you to turn activity tracking on or off individually
    - Displays a list of activities and their time left when you hover the clock in any Neopets page

    I'm sure I missed a few activities. Feel free to request more on https://github.com/saahphire/NeopetsUserscript, or
    through a neomail, or Discord (I'm saahphire in both). GitHub is preferred but I undestand most people don't have an
    account there. I'll only add hunger if someone can provide me withan accurate table listing the time it takes to
    drop from each level. Some non-dailies are random (off the top of my mind, fishing, Faerieland jobs, Igloo, and
    shops) so they can't be added here.

    ✦ ⌇ saahphire
☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦ ⠂⠄⠄⠂⠁⠁⠂⠄⠂⠄⠄⠂☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦ ⠂⠄⠄⠂⠁⠁⠂⠄⠂⠄⠄⠂☆ ⠂⠄⠄⠂⠁⠁⠂⠄⠄⠂✦
........................................................................................................................
•:•.•:•.•:•:•:•:•:•:•:••:•.•:•.•:•:•:•:•:•:•:•:•.•:•.•:•:•:•:•:•:•:••:•.•:•.•:•.•:•:•:•:•:•:•:•:•.•:•:•.•:•.••:•.•:•.••:
*/

// Set an activity to false if you don't want it to be tracked, and true if you do. Do NOT delete or rename entries.
const activityToggles = {
    'Snowager': true,
    'Deadly Dice': false,
    'Obelisk': true,
    'Wheel of Excitement': true,
    'Wheel of Mediocrity': true,
    'Wheel of Misfortune': true,
    'Healing Springs': true,
    'Buried Treasure': true,
    'Illusen/Jhudora': true,
    'Coltzan': true,
    'Grave Danger': true,
    'Expellibox': true,
    'Swashbuckling Academy': true,
    'Training School': true,
    'Secret Training School': true,
    'Edna': true,
    'Esophagor': true
}

const activities = [
    {
        name: 'Snowager',
        url: 'winter/snowager.phtml',
        timestamp: (skipCurrent = false) => getTimes([6, 14, 22], skipCurrent),
        expiration: 60,
        image: 'data:image/png;base64,',
        watch: () => true
    },
    {
        name: 'Deadly Dice',
        url: 'worlds/deadlydice.phtml',
        timestamp: (skipCurrent = false) => getTimes([0], skipCurrent),
        expiration: 60,
        image: 'data:image/png;base64,',
        watch: () => true
    },
    {
        name: 'Obelisk',
        url: 'prehistoric/battleground/',
        timestamp: () => obeliskTimestamp(),
        image: 'data:image/png;base64,',
        watch: () => true
    },
    {
        name: 'Wheel of Excitement',
        url: 'faerieland/wheel.phtml',
        timestamp: () => addMinutes(120),
        image: 'data:image/png;base64,',
        watch: () => hasWheelBeenSpun()
    },
    {
        name: 'Wheel of Mediocrity',
        on: true,
        url: 'prehistoric/mediocrity.phtml',
        timestamp: () => addMinutes(40),
        watch: () => hasWheelBeenSpun()
    },
    {
        name: 'Wheel of Misfortune',
        url: 'halloween/wheel/index.phtml',
        timestamp: () => addMinutes(120),
        watch: () => hasWheelBeenSpun()
    },
    {
        name: 'Healing Springs',
        url: 'faerieland/springs.phtml',
        timestamp: () => addMinutes(30),
        watch: () => document.getElementsByClassName('faerie-bye').length !== 0
    },
    {
        name: 'Buried Treasure',
        url: 'pirates/buriedtreasure/buriedtreasure.phtml?',
        timestamp: () => addMinutes(180),
        watch: () => document.querySelector('.content > div > p > b')
    },
    {
        name: 'Illusen/Jhudora',
        url: 'faerieland/darkfaerie.phtml',
        timestamp: () => addMinutes(720),
        watch: () => document.querySelector('.faerie-img + p font[color="purple"]')
    },
    {
        name: 'Illusen/Jhudora',
        url: 'medieval/earthfaerie.phtml',
        timestamp: () => addMinutes(720),
        watch: () => document.querySelector('.faerie-img + p font[color="green"]')
    },
    {
        name: 'Coltzan',
        url: 'desert/shrine.phtml',
        timestamp: () => addMinutes(780),
        watch: () => document.querySelector('input[value="Back to the Lost Desert"]')
    },
    {
        name: 'Grave Danger',
        match: 'halloween\\/gravedanger',
        url: 'halloween/gravedanger/',
        timestamp: () => graveDangerTimestamp(),
        watch: () => document.getElementById('gdRemaining')
    },
    {
        name: 'Expellibox',
        url: 'games/giveaway/process_giveaway.phtml',
        timestamp: () => addMinutes(427),
        watch: () => !document.body.textContent.startsWith('success=0')
    },
    {
        name: 'Swashbuckling Academy',
        url: 'pirates/academy.phtml?type=status',
        timestamp: () => trainingTimestamp(),
        watch: () => document.querySelector('td + td > br + b')
    },
    {
        name: 'Training School',
        url: 'island/training.phtml?type=status',
        timestamp: () => trainingTimestamp(),
        watch: () => document.querySelector('td + td > br + b')
    },
    {
        name: 'Secret Training School',
        url: 'island/fight_training.phtml?type=status',
        timestamp: () => trainingTimestamp(),
        watch: () => document.querySelector('td + td > br + b')
    },
    {
        name: 'Edna',
        url: 'halloween/witchtower.phtml',
        timestamp: () => ednaTimestamp(),
        // TODO MutationObserver probably
        watch: () => document.querySelector('b[style="color:darkred"], p[style="color:darkgreen;"]')
    },
    {
        name: 'Esophagor',
        url: 'halloween/esophagor.phtml',
        // TODO not updating?
        timestamp: () => ednaTimestamp(),
        watch: () => document.querySelector('b[style="color:darkred"], p[style="color:darkgreen;"]')
    }
]
const timeFromString = string => string
                                    .match(/\d+/g)
                                    .map((n, i) => parseInt(n) * [3600, 60, 1][i])
                                    .reduce((agg, curr) => agg + curr, 0) * 1000 + new Date().getTime();

const trainingTimestamp = () => Math.min(...[...document.querySelectorAll('td + td > br + b')].map(time => timeFromString(time.textContent)));

const hasWheelBeenSpun = async () => {
    const success = document.getElementById('spinMessage');
    if(!success || success.textContent !== '') return false; // The wheel has been spun an unknown amount of time ago
    return new Promise(resolve => {
        const observer = new MutationObserver(() => {
            if(success.textContent !== '') {
                observer.disconnect();
                resolve(true);
            }
        });
        observer.observe(success, {childList: true});
    })
}

const obeliskTimestamp = () => {
    const nextMonday = nstTime(new Date(), 0);
    nextMonday.setUTCDate(nextMonday.getDate() + ((1 - nextMonday.getDay() + 7) % 7));
    const controlThursday = new Date(1769068800000);
    const thursday = nstTime(new Date(), 0);
    thursday.setUTCDate(thursday.getDate() + ((4 - thursday.getDay() + 7) % 7));
    if((controlThursday.getTime() - thursday.getTime()) % 1209600000 !== 0) thursday.setUTCDate(thursday.getDate() + 7);
    return Math.min(nextMonday.getTime(), thursday.getTime());
}

const ednaTimestamp = () => {
    const time = document.querySelector('b[style="color:darkred"] + b');
    if(time) return timeFromString(time.textContent);
}

const graveDangerTimestamp = async () => {
    const foundTimer = await new Promise((resolve => {
        const observer = new MutationObserver(() => {
            const timer = document.getElementById('gdRemaining').textContent;
            if(!timer.match(/\d+/g)) return;
            observer.disconnect();
            resolve(timer);
        });
        observer.observe(document.getElementById('gdRemaining'), {childList: true});
    }))
    return timeFromString(foundTimer)
}

const nstTime = (date, hour) => {
    const parts = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/Los_Angeles',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        hourCycle: 'h24'
    }).formatToParts(date);
    const getPart = type => parts.find(p => p.type === type).value;
    const midnight = new Date(date);
    midnight.setMinutes(0);
    midnight.setSeconds(0);
    midnight.setMilliseconds(0);
    midnight.setHours(hour + date.getHours() - parseInt(getPart('hour')));
    return midnight;
}

const addMinutes = minutes => new Date().getTime() + (minutes * 60 * 1000)

const getTimes = (times, skipCurrent) => Math.min(...times.map(time => {
    const now = new Date();
    if(skipCurrent) now.setHours(now.getHours() + 1);
    const timestamp = nstTime(now, time).getTime();
    return timestamp + (timestamp < now.getTime() ? 86400000 : 0);
}));

const getTimeRemaining = timestamp => {
    const timeRemaining = timestamp - (new Date()).getTime();
    const daysRemaining = Math.floor(timeRemaining / (1000 * 60 * 60 * 24));
    const hoursRemaining = Math.floor((timeRemaining - (daysRemaining * 1000 * 60 * 60 * 24)) / (1000 * 60* 60));
    const minutesRemaining = Math.floor((timeRemaining - (hoursRemaining * 1000 * 60 * 60) - (daysRemaining * 1000 * 60 * 60 * 24)) / (1000 * 60));
    const secondsRemaining = Math.floor((timeRemaining - (minutesRemaining * 1000 * 60) - (hoursRemaining * 1000 * 60 * 60) - (daysRemaining * 1000 * 60 * 60 * 24)) / 1000);
    return `${daysRemaining ? daysRemaining + 'd' : ''}${hoursRemaining}h${minutesRemaining}m${secondsRemaining}s`;
}

const buildNotification = activity => {
    return {
        text: 'Click to open it!',
        title: `${activity.name} reset!`,
        image: activity.image,
        onclick: () => GM.openInTab(`https://${activity.name === 'Expellibox' ? 'ncmall' : 'www'}.neopets.com/${activity.url}`)
    }
}

const alertTimers = async channel => {
    const now = new Date().getTime();
    activities.forEach(async activity => {
        if(!activityToggles[activity.name]) return;
        const timestamp = await GM.getValue(activity.name);
        if(!timestamp || timestamp > now) return;
        GM.deleteValue(activity.name);
        if(!activity.expiration || activity.expiration*60*1000 + timestamp > now) {
            GM.notification(buildNotification(activity));
            channel.postMessage('notified');
        }
        if(activity.expiration) GM.setValue(activity.name, await activity.timestamp(true));
    })
}

const makeTimeout = (timeout, channel) => {
    clearTimeout(timeout);
    timeout = setTimeout(() => alertTimers(channel), 60000 + (Math.random() * 5000));
}

const addTimers = async () => {
    const div = document.createElement('div');
    document.querySelector('#nst, .nst')?.insertAdjacentElement('afterEnd', div);
    div.classList.add('saahphire-timers');
    const ul = document.createElement('ul');
    ul.classList.add('nav-top-nst');
    div.appendChild(ul);
    activities.forEach(async activity => {
        const timestamp = await GM.getValue(activity.name);
        if(!timestamp) return;
        const li = document.createElement('li');
        ul.appendChild(li);
        li.innerHTML = `<a href="${activity.url}">${activity.name}</a>: <span class="timestamp" data-timestamp="${timestamp}">${getTimeRemaining(timestamp)}</span>`;
    });
    setInterval(() => ul.querySelectorAll('li span').forEach(span => span.textContent = getTimeRemaining(parseInt(span.dataset.timestamp))), 1000);    
}

const onActivityPage = async activity => {
    const startTimer = await activity.watch();
    if(!startTimer) return;
    const timestamp = await activity.timestamp();
    if(timestamp) GM.setValue(activity.name, timestamp);
    else GM.deleteValue(activity.name);
    document.getElementsByClassName('saahphire-timers')[0].remove();
    addTimers();
}

const initializeAlerts = () => {
    const channel = new BroadcastChannel('saahphire-non-dailies-notification');
    let timeout;
    channel.onmessage = () => makeTimeout(timeout, channel);
    makeTimeout(timeout, channel);
}

const initializeScript = async () => {
    document.head.insertAdjacentHTML('beforeEnd', css);
    initializeAlerts();
    addTimers();
    const currentActivity = activities.find(act => window.location.href.match(/.+:\/\/(?:\w+\.)?neopets.com\/(.+)/)?.[1].startsWith(act.url));
    if(currentActivity) onActivityPage(currentActivity);
    activities.slice(0, 2).forEach(activity => onActivityPage(activity));
}

const stolenStyles = document.getElementById('header') ? {
    color: window.getComputedStyle(document.getElementById('nst')).color,
    border: window.getComputedStyle(document.getElementsByClassName('dropdown')[0]).border,
    background: window.getComputedStyle(document.getElementsByClassName('dropdown')[0]).backgroundColor,
    position: window.getComputedStyle(document.getElementById('main')).position
} : {
    color: 'initial',
    border: 'none',
    background: 'none',
    position: 'static'
}

const css = `<style>
.saahphire-timers {
    grid-column: 7 / 11;
    grid-row: 1 / 3;
    padding-top: 63px;
    position: absolute;
    z-index: 1;
}
.saahphire-timers ul {
    transform: scaleY(0);
    transform-origin: top;
    transition: transform 200ms ease-in-out;
    list-style: none;
    margin: 0;
    padding: 1em;
    background: white;
}
.saahphire-timers a:not(:hover) {
    color: ${stolenStyles.color};
}
#header .saahphire-timers {
    padding-top: 38px;
    width: max-content;
    right: ${stolenStyles.position === 'relative' ? '0' : 'calc((100vw - 1000px) / 2);'};
}
.nav-top__2020 .saahphire-timers ul {
    width: 100%;
    text-align: left;
}
#header .saahphire-timers ul {
    color: ${stolenStyles.color};
    border: ${stolenStyles.border};
    background-color: ${stolenStyles.background};
    font-size: 7.5pt;
    font-weight: bold;
    font-family: Verdana, Arial, Helvetica, sans-serif;
}
#header .saahphire-timers .timestamp {
    font-weight: normal;
}
.saahphire-timers:hover ul, .saahphire-timers ul:hover {
    transform: scaleY(100%);
    transition: transform 200ms ease-in-out;
}

.nav-top-grid__2020 {
    grid-template-rows: 65px 1fr;
}
</style>`;

(function() {
    'use strict';
    initializeScript();
})();
